diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index 5eb807dcb76c..e1d913cd614e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -997,17 +997,37 @@ Value *InstCombinerImpl::SimplifyDemandedUseBits(Instruction *I,
             uint64_t MaskedGEPIndex = HighBitsGEPIndex | MaskedLowBitsGEPIndex;

             if (MaskedGEPIndex != GEPIndex) {
-              auto *GEP = cast<GetElementPtrInst>(II->getArgOperand(0));
-              Builder.SetInsertPoint(I);
-              Type *GEPIndexType =
-                  DL.getIndexType(GEP->getPointerOperand()->getType());
-              Value *MaskedGEP = Builder.CreateGEP(
-                  GEP->getSourceElementType(), InnerPtr,
-                  ConstantInt::get(GEPIndexType, MaskedGEPIndex),
-                  GEP->getName(), GEP->isInBounds());
-
-              replaceOperand(*I, 0, MaskedGEP);
-              return I;
+              Value *GEPArg = II->getArgOperand(0);
+              // Handle both GetElementPtrInst and ConstantExpr GEPs
+              if (auto *GEP = dyn_cast<GetElementPtrInst>(GEPArg)) {
+                Builder.SetInsertPoint(I);
+                Type *GEPIndexType =
+                    DL.getIndexType(GEP->getPointerOperand()->getType());
+                Value *MaskedGEP = Builder.CreateGEP(
+                    GEP->getSourceElementType(), InnerPtr,
+                    ConstantInt::get(GEPIndexType, MaskedGEPIndex),
+                    GEP->getName(), GEP->isInBounds());
+                replaceOperand(*I, 0, MaskedGEP);
+                return I;
+              } else if (auto *CE = dyn_cast<ConstantExpr>(GEPArg)) {
+                // Check if it's a GEP constant expression
+                if (CE->getOpcode() == Instruction::GetElementPtr) {
+                  Builder.SetInsertPoint(I);
+                  Type *GEPIndexType =
+                      DL.getIndexType(CE->getOperand(0)->getType());
+                  // For ConstantExpr GEP, get the source element type from the
+                  // GEP instruction that would be created
+                  Value *AsInst = CE->getAsInstruction();
+                  Type *SrcElemTy = cast<GetElementPtrInst>(AsInst)->getSourceElementType();
+                  Value *MaskedGEP = Builder.CreateGEP(
+                      SrcElemTy, InnerPtr,
+                      ConstantInt::get(GEPIndexType, MaskedGEPIndex),
+                      "gep", false); // ConstantExpr GEPs don't have inbounds flag
+                  AsInst->deleteValue();
+                  replaceOperand(*I, 0, MaskedGEP);
+                  return I;
+                }
+              }
             }
           }
         }

